import React from 'react';
import Button from '../1_atoms/Button';
import blogHeroIllustration from '../../assets/technical/main-header.svg';
import './BlogHeader.css';

function BlogHeader({
  categories,
  searchTerm,
  selectedCategory,
  onSearchChange,
  onCategoryChange,
}) {
  return (
    <header className="blog-header">
      <div className="blog-header__content">
        <div className="blog-header__copy">
          <p className="blog-header__eyebrow">Блог InsureKids</p>
          <h1>Учимся понимать страхование на понятных жизненных примерах</h1>
          <p className="blog-header__lead">
            Ищи нужную тему, быстро переходи к материалам по ситуациям и разбирайся
            в страховании простым языком.
          </p>

          <form className="blog-search" onSubmit={(event) => event.preventDefault()}>
            <input
              type="text"
              placeholder="Какой у вас вопрос?"
              value={searchTerm}
              onChange={(event) => onSearchChange(event.target.value)}
              className="blog-search__input"
            />
            <Button type="submit">Поиск</Button>
          </form>

          <div className="blog-filters">
            <span className="blog-filters__label">Категории</span>
            <div className="blog-filters__buttons">
              {categories.map((category) => (
                <button
                  key={category}
                  type="button"
                  className={`blog-filter-button ${selectedCategory === category ? 'active' : ''}`}
                  onClick={() => onCategoryChange(category)}
                >
                  {category}
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="blog-header__visual">
          <img src={blogHeroIllustration} alt="Иллюстрация блога InsureKids" />
        </div>
      </div>
    </header>
  );
}

export default BlogHeader;
